# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.shareintentapp

import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.widget.Toast

class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        handleIntent(intent)
    }

    private fun handleIntent(intent: Intent) {
        if (intent.action == Intent.ACTION_SEND && intent.type != null) {
            when (intent.type) {
                "text/plain" -> {
                    val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                    processSharedText(sharedText)
                }
                "image/*", "image/jpeg", "image/png" -> {
                    val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                    processSharedImage(imageUri)
                }
                else -> {
                    Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
                }
            }
        } else if (intent.action == Intent.ACTION_SEND_MULTIPLE) {
            val uris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
            uris?.forEach { uri ->
                processSharedImage(uri)
            }
        }
    }

    private fun processSharedText(text: String?) {
        text?.let {
            Toast.makeText(this, "Received text: $it", Toast.LENGTH_SHORT).show()
        }
    }

    private fun processSharedImage(imageUri: Uri?) {
        imageUri?.let {
            Toast.makeText(this, "Received image: $imageUri", Toast.LENGTH_SHORT).show()
        }
    }
}